SELECT m.meeting_id as meetingId, m.title, m.place_name as placeName, m.meeting_date as meetingDate, m.start_time as startTime, m.max_members as maxMembers, m.status, m.content, m.thumbnail_image as thumbnailImage, s.name sportName, CONCAT(r.sido," ",r.sigungu," ",COALESCE(r.dong,"")) regionName, ( SELECT nickname FROM users where user_id = m.host_user_id ) meetingHostName, ( SELECT COUNT(*) FROM meeting_participants mp WHERE mp.meeting_id=m.meeting_id AND mp.status="APPROVED" ) approvedCount FROM meetings m JOIN sports s ON m.sport_id=s.sport_id JOIN regions r ON m.region_id=r.region_id WHERE m.deleted_at IS NULL
AND m.sport_id = #{sportId}
AND s.name = #{sportName}
AND m.meeting_date = #{meetingDate}
AND m.region_id = #{regionId}
